以下是使用C#编写的一个简单的四则运算器示例代码：

```csharp
using System;

namespace Calculator
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("四则运算器");
            Console.WriteLine("请输入第一个数字: ");
            double num1 = Convert.ToDouble(Console.ReadLine());

            Console.WriteLine("请输入运算符 (+, -, *, /): ");
            string op = Console.ReadLine();

            Console.WriteLine("请输入第二个数字: ");
            double num2 = Convert.ToDouble(Console.ReadLine());

            double result = 0.0;
            bool validOperator = true;

            switch (op)
            {
                case "+":
                    result = num1 + num2;
                    break;
                case "-":
                    result = num1 - num2;
                    break;
                case "*":
                    result = num1 * num2;
                    break;
                case "/":
                    if (num2 != 0)
                    {
                        result = num1 / num2;
                    }
                    else
                    {
                        Console.WriteLine("错误：除数不能为零。");
                        validOperator = false;
                    }
                    break;
                default:
                    Console.WriteLine("错误：无效的运算符。");
                    validOperator = false;
                    break;
            }

            if (validOperator)
            {
                Console.WriteLine("结果: " + result);
            }

            Console.ReadLine();
        }
    }
}
```

这个四则运算器能够接受用户输入两个数字和一个运算符，然后根据运算符的选择执行相应的运算，并输出结果。请注意，这只是一个简单的示例，可能不包含完整的错误处理和输入验证。
